function siteLang(){const p=new URLSearchParams(location.search);const requested=p.get('lang')||localStorage.getItem('mobud-site-lang')||navigator.language||'en';if(SITE_LANGS[requested])return requested;if(/^de[-_](ch)/i.test(requested))return 'de-CH';const base=requested.slice(0,2).toLowerCase();return SITE_LANGS[base]?base:'en'}
let currentSiteLang=siteLang();localStorage.setItem('mobud-site-lang',currentSiteLang);document.documentElement.lang=currentSiteLang;
function st(text){return currentSiteLang==='en'?text:(SITE_T[currentSiteLang]?.[text]||text)}
function addLangPicker(){const foot=document.querySelector('.footer-links');if(!foot||document.getElementById('siteLang'))return;const wrap=document.createElement('label');wrap.className='lang-picker';wrap.innerHTML=`🌐 <select id="siteLang">${Object.entries(SITE_LANGS).map(([k,n])=>`<option value="${k}" ${k===currentSiteLang?'selected':''}>${n}</option>`).join('')}</select>`;foot.append(wrap);wrap.querySelector('select').addEventListener('change',e=>{const u=new URL(location.href);u.searchParams.set('lang',e.target.value);localStorage.setItem('mobud-site-lang',e.target.value);location.href=u.toString()})}
function translateStatic(){const walker=document.createTreeWalker(document.body,NodeFilter.SHOW_TEXT,{acceptNode(n){if(!n.nodeValue.trim()||['SCRIPT','STYLE','TEXTAREA'].includes(n.parentElement?.tagName))return NodeFilter.FILTER_REJECT;return NodeFilter.FILTER_ACCEPT}});let n;while(n=walker.nextNode()){const raw=n.nodeValue.trim();const tr=st(raw);if(tr!==raw)n.nodeValue=n.nodeValue.replace(raw,tr)}document.querySelectorAll('[placeholder],[aria-label]').forEach(el=>['placeholder','aria-label'].forEach(a=>{const raw=el.getAttribute(a);if(raw)el.setAttribute(a,st(raw))}));document.querySelectorAll('a[href^="/faq/"],a[href="/"],a[href^="/#"],a[href^="/legal/"],a[href^="/contact/"]').forEach(a=>{const u=new URL(a.getAttribute('href'),location.origin);u.searchParams.set('lang',currentSiteLang);a.setAttribute('href',u.pathname+u.search+u.hash)})}
const menu = document.querySelector('.menu-toggle');
const nav = document.querySelector('.nav-links');
if (menu) menu.addEventListener('click', () => nav.classList.toggle('open'));
document.querySelectorAll('.nav-links a').forEach(a => a.addEventListener('click', () => nav?.classList.remove('open')));
let deferredInstallPrompt = null;
function isIos(){return /iphone|ipad|ipod/i.test(navigator.userAgent)}
function isStandalone(){return window.matchMedia('(display-mode: standalone)').matches||window.navigator.standalone===true}
function showInstallBanner(){if(isStandalone()||document.getElementById('siteInstallBanner'))return;const banner=document.createElement('div');banner.id='siteInstallBanner';banner.className='site-install-banner';banner.innerHTML=`<div><strong>${st('Install MoBud as an app')}</strong><span>${st('Use the webapp fullscreen from your home screen.')}</span></div><div class="site-install-actions"><button type="button" class="site-install-later">${st('Later')}</button><button type="button" class="site-install-now">${st('Install')}</button></div>`;document.body.prepend(banner);banner.querySelector('.site-install-later').addEventListener('click',()=>{sessionStorage.setItem('mobud-site-install-dismissed','1');banner.remove()});banner.querySelector('.site-install-now').addEventListener('click',async()=>{if(deferredInstallPrompt){deferredInstallPrompt.prompt();await deferredInstallPrompt.userChoice;deferredInstallPrompt=null;banner.remove();return}if(isIos()){alert('On iPhone or iPad: tap Share, then “Add to Home Screen”.');return}window.location.href='/app/'})}
window.addEventListener('beforeinstallprompt',event=>{event.preventDefault();deferredInstallPrompt=event;if(!sessionStorage.getItem('mobud-site-install-dismissed'))showInstallBanner()});
window.addEventListener('appinstalled',()=>{deferredInstallPrompt=null;document.getElementById('siteInstallBanner')?.remove()});
window.addEventListener('load',()=>{if(isIos()&&!isStandalone()&&!sessionStorage.getItem('mobud-site-install-dismissed'))showInstallBanner()});
if('serviceWorker'in navigator){window.addEventListener('load',()=>{navigator.serviceWorker.register('/site-service-worker.js',{scope:'/'}).catch(error=>console.warn('Public-site service worker registration failed:',error))})}
async function initFaq(){const list=document.querySelector('#faqList');if(!list)return;const search=document.querySelector('#faqSearch');const buttons=[...document.querySelectorAll('[data-category]')];let category='all';let items=[];try{const res=await fetch('/content/faq.json');items=await res.json()}catch(error){list.innerHTML=`<div class="card">${st('FAQ could not be loaded.')}</div>`;return}const get=(obj)=>obj?.[currentSiteLang]||obj?.en||'';const render=()=>{const q=(search?.value||'').toLowerCase();const filtered=items.filter(item=>{const question=get(item.question).toLowerCase(),answer=get(item.answer).toLowerCase();return (category==='all'||item.category===category)&&(question.includes(q)||answer.includes(q))});list.innerHTML=filtered.map((item,index)=>`<article class="faq-item"><button class="faq-question" aria-expanded="false"><span>${index+1}. ${get(item.question)}</span><span>⌄</span></button><div class="faq-answer">${get(item.answer)}</div></article>`).join('')||`<div class="card">${st('No matching questions.')}</div>`;list.querySelectorAll('.faq-question').forEach(button=>button.addEventListener('click',()=>{const item=button.closest('.faq-item');item.classList.toggle('open');button.setAttribute('aria-expanded',item.classList.contains('open'))}))};buttons.forEach(button=>button.addEventListener('click',()=>{buttons.forEach(other=>other.classList.remove('active'));button.classList.add('active');category=button.dataset.category;render()}));search?.addEventListener('input',render);render()}
addLangPicker();translateStatic();initFaq();
